prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?originalId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:originalId ?originalId ;
         tai:modelCreated ?created .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(CONTAINS(LCASE(STR(?taskName)), "technical support") ||
         CONTAINS(LCASE(STR(?taskName)), "technical") ||
         CONTAINS(LCASE(STR(?taskName)), "support"))
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?originalId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:originalId ?originalId ;
         tai:modelCreated ?created .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task rdfs:comment ?taskComment . }

  FILTER(
    CONTAINS(LCASE(STR(COALESCE(?taskName,""))), "support") ||
    CONTAINS(LCASE(STR(COALESCE(?taskName,""))), "help") ||
    CONTAINS(LCASE(STR(COALESCE(?taskName,""))), "helpdesk") ||
    CONTAINS(LCASE(STR(COALESCE(?taskName,""))), "service") ||
    CONTAINS(LCASE(STR(COALESCE(?taskComment,""))), "support") ||
    CONTAINS(LCASE(STR(COALESCE(?taskComment,""))), "help")
  )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?task ?taskName ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created (COUNT(DISTINCT ?task) AS ?matchedTasks) WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" ;
       tai:belongsTo ?corpus .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), "korisni") ||
    CONTAINS(LCASE(STR(?taskName)), "servis") ||
    CONTAINS(LCASE(STR(?taskName)), "podrš") ||
    CONTAINS(LCASE(STR(?taskName)), "podrz") ||
    CONTAINS(LCASE(STR(?taskName)), "nivoa") ||
    CONTAINS(LCASE(STR(?taskName)), "pomoc") ||
    CONTAINS(LCASE(STR(?taskName)), "help")
  )
}
GROUP BY ?model ?modelName ?created
ORDER BY DESC(?created)
LIMIT 25
